sys_script_include.script:
var SecurityRiskCalculator = Class.create();
SecurityRiskCalculator.prototype = {
    initialize: function() {},

    calculateScore: function(ciSysId, rawThreatScore) {
        // Convert the raw score input into an integer, fallback to 5 if empty
        var finalRiskScore = parseInt(rawThreatScore) || 5; 

        // If no Configuration Item was attached, return the raw score as-is
        if (!ciSysId) return finalRiskScore;

        var ciGr = new GlideRecord('cmdb_ci');
        if (ciGr.get(ciSysId)) {
            // Retrieve the business criticality value of the asset
            var criticality = ciGr.getValue('business_criticality'); 

            // Criticality multipliers: 1 = High/Most Critical, 2 = Medium, 3 = Low
            if (criticality == '1') {
                finalRiskScore += 40; // High criticality asset bump
            } else if (criticality == '2') {
                finalRiskScore += 20; // Medium criticality asset bump
            } else {
                finalRiskScore += 5;  // Low criticality asset bump
            }
        }
        return finalRiskScore;
    },

    type: 'SecurityRiskCalculator'
};
